pub const keep: Action(element)
```
 Action to keep an element.

 This action is typically used to match on remaining elements in a filter function:

 let filter: filter.BlockFilter = fn(block, _meta) {
   case block {
     // match and process specific elements, then... 
     _ -> filter.keep // ...keep the remaining elements (and filter their children)
   }
 }


 Note that children of the kept element will be filtered.
Synonyms:
pandi/filter.keep
pandi/filter keep

This module aims to make it easy to create *document filters*,
i.e. element-processing functions that can be applied to the whole document tree.
The types guarantee a valid document at the end; infinite recursion loops will never happen.

Below is a complete example converting ordered lists to bullet lists (block converter),
and converting occurences like gh:lustre-labs/lustre to a Github link (inline converter):

```gleam 
import pandi/doc
import pandi/filter

pub fn main() {
  let change_ordered_to_bullet_list: filter.BlockFilter = fn(block, _meta) {
    case block {
      doc.OrderedList(_, items) -> [doc.BulletList(items)] |> filter.replace
      _ -> filter.keep
    }
  }

  let empty_attributes = doc.Attributes(id: "", classes: [], keyvalues: [])
  let insert_github_links: filter.InlineFilter = fn(inline, _meta) {
    case inline {
      doc.Str("gh:" <> repo) ->
        [
          doc.Link(
            attributes: empty_attributes,
            content: doc.text(repo),
            target: doc.Target(
              url: "https://github.com/" <> repo,
              title: repo <> " at Github",
            ),
          ),
        ]
        |> filter.replace
      _ -> filter.keep
    }
  }

  let list_attributes = doc.ListAttributes(1, doc.Decimal, doc.Period)
  let document =
    doc.Document(
      blocks: [
        doc.OrderedList(list_attributes, [
          [doc.Plain([doc.Str("gh:lustre-labs/lustre")])],
          [doc.Plain([doc.Str("gh:giacomocavalieri/squirrel")])],
        ]),
      ],
      meta: [],
    )

  document
  |> filter.apply_block_filter(change_ordered_to_bullet_list)
  |> filter.apply_inline_filter(insert_github_links)
  |> doc.to_string
  // [
  //   BulletList
  //     [
  //       [
  //         Plain
  //           [
  //             Link
  //               ( "" , [  ] , [  ] )
  //               [ Str "lustre-labs/lustre" ]
  //               (
  //                 "https://github.com/lustre-labs/lustre" ,
  //                 "lustre-labs/lustre at Github" ,
  //               ) ,
  //           ] ,
  //       ] ,
  //       [
  //         Plain
  //           [
  //             Link
  //               ( "" , [  ] , [  ] )
  //               [ Str "giacomocavalieri/squirrel" ]
  //               (
  //                 "https://github.com/giacomocavalieri/squirrel" ,
  //                 "giacomocavalieri/squirrel at Github" ,
  //               ) ,
  //           ] ,
  //       ] ,
  //     ] ,
  // ]
}
